import { Box, Button, Container, Divider, Grid, IconButton, makeStyles, Paper, Typography } from '@material-ui/core'
import { ChevronLeftRounded } from '@material-ui/icons'
import axios from 'axios'
import React, { useEffect, useState } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import { format } from 'date-fns'

const useStyle = makeStyles(theme => {
    return {
        activity: {
            padding: theme.spacing(2),
            width: '100%'
        },
        btn: {
            marginTop: theme.spacing(2)
        }
    }
})

function StudentActivity() {
    const classes = useStyle()

    const [post, setPost] = useState({});

    const { id } = useParams();
    async function getPost() {
        const sendData = {
            updateID: id
        };

       await axios.post('https://ursacapi.000webhostapp.com/api/getPostID.php', JSON.stringify(sendData))
            .then(response => {
                if (response.data == 0) {
                    console.log('post ID not found');
                } else {
                    setPost(response.data[0]);
                }
            })
            
    
    }

   const navigate = useNavigate();
//    const currentDate = post.dateCreated;

//     function datePosted (currentDate) {
//         return format(new Date(currentDate), 'dd/MM/yyyy')
//     }
    

    useEffect(() => {
        getPost();
    }, []);

    

    return (
        <Box>
            <IconButton onClick={() => navigate(-1)} >
            <ChevronLeftRounded />
          </IconButton>
            <Container>
                <Grid container spacing={2} justifyContent="space-evenly" >
                    <Grid item xs={12} md={6}>
                        <Paper className={classes.activity} elevation={0} square={true} variant='outlined' >
                            <Typography variant='h4' >
                                {post.title}
                            </Typography>


                            <Grid container spacing={1}>
                                <Grid item xs={12} md={5}>
                                    <Typography variant='caption' >
                                        {post.nameWhoPosted} 
                                    </Typography>
                                </Grid>
                                <Grid item xs={12} md={1}>
                                    <Typography variant='body1' >
                                    •
                                    </Typography>
                                </Grid>
                                <Grid item xs={12} md={2}>
                                    <Typography variant='caption' >
                                        {post.dateCreated}
                                    </Typography>
                                </Grid>
                            </Grid>




                            <Typography variant='body1' >
                                100 points
                            </Typography>

                            <Divider />

                            <Typography variant='body2' >
                                {post.body}something
                                something asokdjhalkjhsdoihjuawokenm oaisjdlkahjw asjdlkjawlijed askoldjhasdjkljasdj pajoskdikjawioj asopjdoikjasd

                            </Typography>


                        </Paper>
                    </Grid>

                    <Grid item xs={12} md={1}></Grid>

                    <Grid item xs={12} md={5}>
                        <Paper className={classes.activity}>

                        <Grid container justifyContent="space-between" alignContent='center' >
                                <Grid item>
                                    <Typography variant='h6' >
                                        Your work
                                    </Typography>
                                </Grid>
                                <Grid item>
                                    <Typography variant='caption' color='error'  >
                                        Missing
                                    </Typography>
                                </Grid>
                            </Grid>


                            <Button className={classes.btn} color='secondary' variant='outlined' fullWidth >
                                Upload file
                            </Button>

                            <Button className={classes.btn} color='secondary' variant='contained' fullWidth >
                                Submit work
                            </Button>
                        </Paper>
                    </Grid>

                </Grid>

            </Container>
        </Box>
    )
}

export default StudentActivity
